 91		if err != nil {
 92			return nil, fmt.Errorf("failed to read config file %s: %w", path, err)
 93		}
 94	
 95		// Validate using two-phase validation
 96		if err := cl.validator.Validate(data); err != nil {
 97			return nil, fmt.Errorf("configuration validation failed: %w", err)
 98		}
 99	
100		// Parse YAML into new config structure
101		var config NewConfig
102		if err := yaml.Unmarshal(data, &config); err != nil {
103			return nil, fmt.Errorf("failed to parse config YAML from %s: %w", path, err)
